registerModule('Movement Trail', function(g) {
  g._trail = g._trail || {
    points: [],
    maxLength: 48,
    lastX: g.px,
    lastY: g.py
  };

  var trail = g._trail;
  var ctx = g.ctx;
  var dx = g.px - trail.lastX;
  var dy = g.py - trail.lastY;
  var moved = dx * dx + dy * dy > 0.1;

  if (moved) {
    trail.points.push({ x: g.px, y: g.py, age: 0 });
    if (trail.points.length > trail.maxLength) {
      trail.points.shift();
    }
    trail.lastX = g.px;
    trail.lastY = g.py;
  }

  var len = trail.points.length;
  if (len < 2) return;

  for (var i = 1; i < len; i++) {
    var pt = trail.points[i];
    var prev = trail.points[i - 1];
    var t = i / len;
    var alpha = t * t * 0.85;
    var size = t * 3.2;

    // Color shifts from teal to violet as it fades back
    var r = Math.round(g.lerp(160, 0, t));
    var green = Math.round(g.lerp(80, 255, t));
    var b = Math.round(g.lerp(255, 170, t));

    ctx.save();
    ctx.strokeStyle = 'rgba(' + r + ',' + green + ',' + b + ',' + alpha + ')';
    ctx.lineWidth = size;
    ctx.lineCap = 'round';
    ctx.shadowColor = 'rgba(' + r + ',' + green + ',' + b + ',' + (alpha * 0.6) + ')';
    ctx.shadowBlur = size * 2.5;
    ctx.beginPath();
    ctx.moveTo(prev.x, prev.y);
    ctx.lineTo(pt.x, pt.y);
    ctx.stroke();
    ctx.restore();
  }

  // Sparkle particles occasionally shed from trail tail
  if (moved && len > 8 && g.tick % 4 === 0) {
    var tip = trail.points[0];
    g.particles.push({
      x: tip.x + g.rand(-2, 2),
      y: tip.y + g.rand(-2, 2),
      vx: g.rand(-0.4, 0.4),
      vy: g.rand(-0.4, 0.4),
      life: 1,
      decay: g.rand(0.03, 0.06),
      r: 120, gr: 80, b: 255,
      size: g.rand(0.8, 1.8)
    });
  }

  // Render and age particles
  for (var j = g.particles.length - 1; j >= 0; j--) {
    var p = g.particles[j];
    if (p.life === undefined) continue;
    p.x += p.vx;
    p.y += p.vy;
    p.life -= p.decay;
    if (p.life <= 0) {
      g.particles.splice(j, 1);
      continue;
    }
    ctx.save();
    ctx.globalAlpha = p.life * p.life;
    ctx.fillStyle = 'rgb(' + p.r + ',' + p.gr + ',' + p.b + ')';
    ctx.shadowColor = ctx.fillStyle;
    ctx.shadowBlur = 4;
    ctx.fillRect(p.x - p.size / 2, p.y - p.size / 2, p.size, p.size);
    ctx.restore();
  }
})

registerModule('Ambient Starfield', function(g) {
  g._stars = g._stars || (function() {
    var arr = [];
    for (var i = 0; i < 200; i++) {
      arr.push({
        x: Math.random() * 800,
        y: Math.random() * 600,
        z: Math.random(),
        vx: (Math.random() - 0.5) * 0.08,
        vy: (Math.random() - 0.5) * 0.08,
        twinkle: Math.random() * Math.PI * 2,
        twinkleSpeed: 0.01 + Math.random() * 0.04,
        baseSize: 0.4 + Math.random() * 1.4,
        hue: Math.random() < 0.15 ? (Math.random() < 0.5 ? 200 : 280) : 0,
        sat: Math.random() < 0.15 ? (40 + Math.random() * 40) : 0
      });
    }
    return arr;
  })();

  var ctx = g.ctx;
  var W = g.canvas.width;
  var H = g.canvas.height;
  var stars = g._stars;

  for (var i = 0; i < stars.length; i++) {
    var s = stars[i];

    s.x += s.vx;
    s.y += s.vy;
    s.twinkle += s.twinkleSpeed;

    if (s.x < 0) s.x = W;
    if (s.x > W) s.x = 0;
    if (s.y < 0) s.y = H;
    if (s.y > H) s.y = 0;

    var twinkleFactor = 0.5 + 0.5 * Math.sin(s.twinkle);
    var alpha = 0.2 + twinkleFactor * (0.4 + s.z * 0.4);
    var size = s.baseSize * (0.7 + twinkleFactor * 0.5);

    if (s.hue === 0) {
      var brightness = Math.floor(180 + twinkleFactor * 75);
      ctx.fillStyle = 'rgba(' + brightness + ',' + brightness + ',' + (brightness + 20 | 0) + ',' + alpha.toFixed(2) + ')';
    } else {
      ctx.fillStyle = 'hsla(' + s.hue + ',' + s.sat + '%,80%,' + alpha.toFixed(2) + ')';
    }

    if (s.z > 0.7 && twinkleFactor > 0.8) {
      ctx.beginPath();
      var r = size * 1.8;
      ctx.arc(s.x, s.y, r * 1.5, 0, Math.PI * 2);
      if (s.hue === 0) {
        ctx.fillStyle = 'rgba(200,220,255,' + (alpha * 0.08).toFixed(3) + ')';
      } else {
        ctx.fillStyle = 'hsla(' + s.hue + ',' + s.sat + '%,90%,' + (alpha * 0.1).toFixed(3) + ')';
      }
      ctx.fill();

      if (s.hue === 0) {
        var b2 = Math.floor(180 + twinkleFactor * 75);
        ctx.fillStyle = 'rgba(' + b2 + ',' + b2 + ',' + (b2 + 20 | 0) + ',' + alpha.toFixed(2) + ')';
      } else {
        ctx.fillStyle = 'hsla(' + s.hue + ',' + s.sat + '%,80%,' + alpha.toFixed(2) + ')';
      }
    }

    ctx.beginPath();
    ctx.arc(s.x, s.y, size, 0, Math.PI * 2);
    ctx.fill();
  }
})
